export class SoundManager {
  private static instance: SoundManager;

  musicVolume: number = 50;
  sfxVolume: number = 50;
  
  private musicCache: Map<string, HTMLAudioElement> = new Map();
  private sfxCache: Map<string, HTMLAudioElement> = new Map();
  private currentMusic: HTMLAudioElement | null = null;

  private constructor() {
    this.loadSettings();
  }

  static getInstance(): SoundManager {
    if (!SoundManager.instance) {
      SoundManager.instance = new SoundManager();
    }
    return SoundManager.instance;
  }

  async loadAll(): Promise<void> {
    const sfxList = ['move_cursor', 'select', 'move_unit', 'attack', 'ability', 'shop_buy', 'combat_end', 'hit', 'dodge'];
    const musicList = ['battle', 'menu', 'victory', 'defeat'];

    for (const id of sfxList) {
      const audio = new Audio(`/audio/sfx/${id}.mp3`);
      this.sfxCache.set(id, audio);
    }
    for (const id of musicList) {
      const audio = new Audio(`/audio/music/${id}.mp3`);
      audio.loop = true;
      this.musicCache.set(id, audio);
    }
  }

  saveSettings(): void {
    const data = {
      musicVolume: this.musicVolume,
      sfxVolume: this.sfxVolume,
    };
    localStorage.setItem('survivors2_audio', JSON.stringify(data));
    this.applyVolumes();
  }

  loadSettings(): void {
    const saved = localStorage.getItem('survivors2_audio');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        this.musicVolume = typeof data.musicVolume === 'number' ? data.musicVolume : 50;
        this.sfxVolume = typeof data.sfxVolume === 'number' ? data.sfxVolume : 50;
      } catch (e) {
        console.warn('Failed to parse audio settings.');
      }
    }
    this.applyVolumes();
  }

  setMusicVolume(vol: number): void {
    this.musicVolume = Math.max(0, Math.min(100, vol));
    this.saveSettings();
  }

  setSfxVolume(vol: number): void {
    this.sfxVolume = Math.max(0, Math.min(100, vol));
    this.saveSettings();
  }

  private applyVolumes(): void {
    if (this.currentMusic) {
      this.currentMusic.volume = this.musicVolume / 100;
    }
  }

  playMusic(id: string): void {
    if (this.currentMusic) {
      this.currentMusic.pause();
      this.currentMusic.currentTime = 0;
    }
    const track = this.musicCache.get(id);
    if (track) {
      this.currentMusic = track;
      track.volume = this.musicVolume / 100;
      track.play().catch(e => console.warn('Music play prevented by browser restrictions', e));
    }
  }

  playSound(id: string): void {
    const sfx = this.sfxCache.get(id);
    if (sfx) {
      const clone = sfx.cloneNode() as HTMLAudioElement;
      clone.volume = this.sfxVolume / 100;
      clone.play().catch(e => console.warn('SFX play prevented by browser restrictions', e));
    }
  }
}
