import { getAbilityData } from '../database/AbilityDatabase.ts';
import { BattleManager } from '../systems/BattleManager.ts';
import { EnemyArmyGenerator } from '../systems/EnemyArmyGenerator.ts';
import { SpawnSystem } from '../systems/SpawnSystem.ts';
import { getAllUnitData } from '../database/UnitDatabase.ts';
import { LayoutManager } from '../ui/LayoutManager.ts';
import { DeploymentSystem } from '../systems/DeploymentSystem.ts';
import { EmptyTileMenu } from '../ui/EmptyTileMenu.ts';

// ─── Game Orchestrator ─────────────────────────────────────────────────────────

export class Game {
  // Canvas
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;

  // Core
  private map: GameMap | undefined;
  private unitManager: UnitManager = new UnitManager();
  private economy: EconomySystem = new EconomySystem();
  private battleManager: BattleManager = new BattleManager();
  private deploymentSystem: DeploymentSystem = new DeploymentSystem();
  private camera: Camera = new Camera();
  private cursor: Cursor = new Cursor();

  // Renderers
  private mapRenderer: MapRenderer;
  private unitRenderer: UnitRenderer;

  // UI
  private unitMenu: UnitMenu = new UnitMenu();
  private hud: HUD;
  private shopMenu: ShopMenu = new ShopMenu();
  private mainMenu: MainMenu = new MainMenu();
  private battleResult: BattleResultScreen = new BattleResultScreen();
  private enemyInfoPanel: EnemyInfoPanel = new EnemyInfoPanel();
  private combatLog: CombatLog = new CombatLog();
  private notificationRenderer: NotificationRenderer = new NotificationRenderer();
  private layoutManager: LayoutManager = new LayoutManager();
  private emptyTileMenu: EmptyTileMenu = new EmptyTileMenu();

  // State
  private phase: GamePhase = GamePhase.MAIN_MENU;
  private isPostMoveAction: boolean = false; // True when showing menu after moving
  private turnNumber: number = 1;
  private selectedUnit: Unit | null = null;
  private selectedAbilityId: string | null = null;
  private reachableTiles: Position[] = [];
  private attackableTiles: Position[] = [];
  private pathPreview: Position[] = [];
  private enemiesDefeatedThisBattle: number = 0;
  private initialEnemyCount: number = 0;

  // AI
  private aiActions: AIAction[] = [];
  private aiActionIndex: number = 0;
  private aiTimer: number = 0;
  private aiMoving: boolean = false;
  private aiMovePathIndex: number = 0;
  private aiWaitingToAttack: boolean = false;

  // Animation
  private movePath: Position[] = [];
  private movePathIndex: number = 0;
  private moveTimer: number = 0;

  // Combat animation
  private combatAnimTimer: number = 0;
  private pendingCombatAttacker: Unit | null = null;
  private pendingCombatDefender: Unit | null = null;

  // Damage popups
  private damagePopups: { x: number; y: number; text: string; timer: number; color: string }[] = [];

  // Input cooldown
  private inputCooldown: number = 0;
  private lastTime: number = 0;

  constructor(canvas: HTMLCanvasElement) {
    this.canvas = canvas;
    canvas.width = GameConfig.CANVAS_WIDTH;
    canvas.height = GameConfig.CANVAS_HEIGHT;
    this.ctx = canvas.getContext('2d')!;

    this.mapRenderer = new MapRenderer(this.ctx);
    this.unitRenderer = new UnitRenderer(this.ctx);
    this.hud = new HUD(this.ctx);

    this.setupInput();
  }

  // ─── Initialization ────────────────────────────────────────────────────────
  async loadMap(url: string): Promise<void> {
    const resp = await fetch(url);
    const data: MapData = await resp.json();
    this.initMapData(data);
  }

  private initMapData(data: MapData): void {
    this.map = new GameMap(data);
    // Note: unitManager is NOT reset here to allow player unit persistence
    this.startNewBattle();
  }

  private startNewBattle(): void {
    const playerUnits = this.unitManager.getTeamUnits(Team.PLAYER);
    
    // 1. Clear enemies from previous battle
    const enemies = this.unitManager.getTeamUnits(Team.ENEMY);
    for (const e of enemies) this.unitManager.removeUnit(e.id);
    
    // 2. Spawn player units in a group
    const playerSpawns = SpawnSystem.getPlayerSpawnPositions(this.map!, playerUnits.length);
    for (let i = 0; i < playerUnits.length; i++) {
      const spawn = playerSpawns[i] || { x: 0, y: 0 };
      playerUnits[i].position = { ...spawn };
      playerUnits[i].animX = spawn.x;
      playerUnits[i].animY = spawn.y;
    }

    // 3. Generate and spawn procedural enemies
    const enemyTemplates = EnemyArmyGenerator.generateArmy(this.battleManager.enemyGoldBudget);
    const enemySpawns = SpawnSystem.getEnemySpawnPositions(
      this.map!, 
      enemyTemplates.length, 
      playerUnits.map(u => u.position),
      this.unitManager
    );

    for (let i = 0; i < enemyTemplates.length; i++) {
        const spawn = enemySpawns[i];
        if (!spawn) continue;
        const enemy = createUnit(enemyTemplates[i].id, Team.ENEMY, spawn);
        this.unitManager.addUnit(enemy);
    }

    this.initialEnemyCount = this.unitManager.getTeamUnits(Team.ENEMY).length;
    this.enemiesDefeatedThisBattle = 0;

    // Center camera on players or map start
    if (playerUnits.length > 0) {
      this.cursor.setPosition(playerUnits[0].position.x, playerUnits[0].position.y);
    } else {
      this.cursor.setPosition(0, 0);
    }
    this.camera.follow(this.cursor.x, this.cursor.y, this.map!.width, this.map!.height);

    this.turnNumber = 1;
    this.phase = GamePhase.DEPLOYMENT_PHASE;
    this.isPostMoveAction = false;
    
    // Initialize deployment: set up deployment zones and position player units
    this.deploymentSystem.initializeDeploymentZones(this.map!.width, this.map!.height);
    for (const unit of playerUnits) {
      this.deploymentSystem.placeUnit(unit, unit.position.x, unit.position.y);
    }
    
    this.hud.showPhaseBanner(`BATTLE ${this.battleManager.currentBattleNumber} - DEPLOYMENT`);
    this.combatLog.addMessage(`Battle ${this.battleManager.currentBattleNumber} Start! Position your units.`);
  }

  private generateNewMap(): void {
    // Don't pass width/height to use random sizing
    const mapData = MapGenerator.generate();
    this.initMapData(mapData);
  }

  startMainMenu(): void {
    this.phase = GamePhase.MAIN_MENU;
    this.mainMenu.reset();
    this.start();
  }

  startNewCampaign(): void {
    // Reset everything for a fresh start
    this.unitManager = new UnitManager();
    resetUnitIdCounter();
    this.economy = new EconomySystem(GameConfig.STARTING_GOLD);
    this.battleManager = new BattleManager();
    
    // Start with Shop phase
    this.phase = GamePhase.SHOP;
    this.shopMenu.open();
    
    if (!this.lastTime) this.start();
  }

  private start(): void {
    this.lastTime = performance.now();
    requestAnimationFrame((t) => this.gameLoop(t));
  }

  // ─── Game Loop ─────────────────────────────────────────────────────────────
  private gameLoop(time: number): void {
    const dt = time - this.lastTime;
    this.lastTime = time;

    this.update(dt, time);
    this.render(time);

    requestAnimationFrame((t) => this.gameLoop(t));
  }

  // ─── Update ────────────────────────────────────────────────────────────────
  private update(dt: number, time: number): void {
    if (this.inputCooldown > 0) this.inputCooldown -= dt;

    this.cursor.update(dt);
    this.hud.update(dt);
    this.shopMenu.update(dt);
    this.combatLog.update(time);
    this.notificationRenderer.update(dt);
    this.updateDamagePopups(dt);
    this.updateDeathAnimations(dt);
    this.updateUnitOffsets(dt);

    if (this.phase === GamePhase.ANIMATION) {
      this.updateMoveAnimation(dt);
    }

    if (this.phase === GamePhase.COMBAT_ANIMATION) {
      this.updateCombatAnimation(dt);
    }

    if (this.phase === GamePhase.ENEMY_TURN) {
      this.updateAITurn(dt);
    }
  }

  // ─── Move Animation ────────────────────────────────────────────────────────
  private updateMoveAnimation(dt: number): void {
    if (!this.selectedUnit || this.movePath.length === 0) return;

    this.moveTimer += dt;
    const moveInterval = 1000 / GameConfig.MOVE_SPEED;

    if (this.moveTimer >= moveInterval) {
      this.moveTimer = 0;
      this.movePathIndex++;

      if (this.movePathIndex >= this.movePath.length) {
        // Movement complete
        const dest = this.movePath[this.movePath.length - 1];
        this.selectedUnit.position = { ...dest };
        this.selectedUnit.animX = dest.x;
        this.selectedUnit.animY = dest.y;
        this.selectedUnit.isMoving = false;
        this.movePath = [];
        this.movePathIndex = 0;

        // Open Action menu after moving
        this.isPostMoveAction = true;
        this.unitMenu.open(this.selectedUnit);
        this.unitMenu.options = ['Attack', 'Wait']; // Simplified post-move options
        if (this.selectedUnit.abilities.length > 0) {
          const abilityId = this.selectedUnit.abilities[0];
          const ability = getAbilityData(abilityId);
          // Only show "Ability" if they have enough MP
          if (ability && this.selectedUnit.currentMP >= ability.mpCost) {
            this.unitMenu.options.splice(1, 0, 'Ability');
          }
        }
        this.phase = GamePhase.MENU_OPEN;
      } else {
        const pos = this.movePath[this.movePathIndex];
        this.selectedUnit.animX = pos.x;
        this.selectedUnit.animY = pos.y;
      }
    }
  }

  private showAttackRange(): void {
    if (!this.selectedUnit || !this.map) return;

    const attackTiles = getAttackableTiles(
      this.selectedUnit.position.x,
      this.selectedUnit.position.y,
      this.selectedUnit.attackRange,
      this.map
    );

    // Filter to only tiles with enemies
    this.attackableTiles = attackTiles.filter((t) => {
      const u = this.unitManager.getUnitAt(t);
      return u && u.team !== this.selectedUnit!.team;
    });

    if (this.attackableTiles.length > 0) {
      this.phase = GamePhase.SELECTING_ATTACK_TARGET;
      // Position cursor on first attackable
      this.cursor.setPosition(this.attackableTiles[0].x, this.attackableTiles[0].y);
    } else {
      // No enemies in range, cannot attack — return to action menu
      this.attackableTiles = [];
      this.unitMenu.open(this.selectedUnit);
      this.phase = GamePhase.MENU_OPEN;
    }
  }

  private showAbilityRange(): void {
    if (!this.selectedUnit || !this.selectedAbilityId || !this.map) return;

    const ability = getAbilityData(this.selectedAbilityId);
    if (!ability) return;

    const tiles = getAttackableTiles(
      this.selectedUnit.position.x,
      this.selectedUnit.position.y,
      ability.range,
      this.map
    );

    // Filter by type
    this.attackableTiles = tiles.filter((t) => {
      const u = this.unitManager.getUnitAt(t);
      if (!u) return false;
      if (ability.type === 'attack' && u.team !== this.selectedUnit!.team) return true;
      if (ability.type === 'heal' && u.team === this.selectedUnit!.team) return true;
      return false;
    });

    if (this.attackableTiles.length > 0) {
      this.phase = GamePhase.SELECTING_ABILITY_TARGET;
      this.cursor.setPosition(this.attackableTiles[0].x, this.attackableTiles[0].y);
    } else {
      // Nothing in range
      this.attackableTiles = [];
      this.selectedAbilityId = null;
      this.unitMenu.open(this.selectedUnit);
      this.phase = GamePhase.MENU_OPEN;
    }
  }

  // ─── Combat Animation ──────────────────────────────────────────────────────
  private updateCombatAnimation(dt: number): void {
    this.combatAnimTimer -= dt;
    if (this.combatAnimTimer <= 0) {
      if (this.pendingCombatAttacker && this.pendingCombatDefender) {
        this.finalizeCombat(this.pendingCombatAttacker, this.pendingCombatDefender);
      }
      this.pendingCombatAttacker = null;
      this.pendingCombatDefender = null;

      if (this.phase === GamePhase.COMBAT_ANIMATION) {
        this.phase = GamePhase.PLAYER_TURN;
        this.checkWinLose();
        this.checkTurnEnd();
      }
    }
  }

  private startCombat(attacker: Unit, defender: Unit): void {
    this.pendingCombatAttacker = attacker;
    this.pendingCombatDefender = defender;
    attacker.flashTimer = 0.3;
    defender.flashTimer = 0.3;
    this.combatAnimTimer = 500; // ms
    this.phase = GamePhase.COMBAT_ANIMATION;
  }

  private finalizeCombat(attacker: Unit, defender: Unit): void {
    const result = executeCombat(attacker, defender, this.map!);

    // Damage popup
    this.damagePopups.push({
      x: defender.position.x,
      y: defender.position.y,
      text: result.damage > 0 ? `-${result.damage}` : 'MISS',
      timer: 1.2,
      color: result.damage > 0 ? '#FF4444' : '#AAAAAA',
    });

    if (result.isHit) {
      SoundManager.getInstance().playSound('hit');
      defender.flashTimer = 0.3;
      // Hit recoil
      const dx = defender.position.x - attacker.position.x;
      const dy = defender.position.y - attacker.position.y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;
      defender.offsetX = (dx / dist) * 12;
      defender.offsetY = (dy / dist) * 12;
    } else {
      SoundManager.getInstance().playSound('dodge');
      // Dodge jump
      const dx = defender.position.x - attacker.position.x;
      const dy = defender.position.y - attacker.position.y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;
      defender.offsetX = (dx / dist) * -12 + (Math.random() > 0.5 ? 8 : -8);
      defender.offsetY = (dy / dist) * -12 + (Math.random() > 0.5 ? 8 : -8);
    }

    // Log the event
    if (result.isCrit) {
      this.combatLog.addMessage(`${attacker.name} rolled 20 -> Critical Hit!`);
    } else if (result.isCritFail) {
      this.combatLog.addMessage(`${attacker.name} rolled 1 -> Critical Fail`);
    } else {
      const hitText = result.isHit ? `Hit` : `Miss`;
      this.combatLog.addMessage(`${attacker.name} rolled ${result.attackRoll} vs CA ${result.targetAC} -> ${hitText}`);
    }

    if (result.isHit) {
      this.combatLog.addMessage(`${attacker.name} dealt ${result.damage} damage`);
    }

    // XP
    grantAttackXP(attacker);
    if (result.defenderDied) {
      grantKillXP(attacker);
      defender.isDying = true;
      if (defender.team === Team.ENEMY) {
        this.combatLog.addMessage(`Enemy ${defender.name} was defeated`);
        this.enemiesDefeatedThisBattle++;
      } else {
         this.combatLog.addMessage(`Ally ${defender.name} fell in combat`);
      }
    }

    // Level up check
    if (canLevelUp(attacker)) {
      const gains = applyLevelUp(attacker);
      this.combatLog.addMessage(`${attacker.name} leveled up to Lv ${attacker.level}!`);
      this.damagePopups.push({
        x: attacker.position.x,
        y: attacker.position.y,
        text: `LV UP!`,
        timer: 2,
        color: '#FFD700',
      });
    }

    attacker.hasActed = true;
    attacker.flashTimer = 0;
    defender.flashTimer = 0;
  }

  private finalizeAbility(attacker: Unit, defender: Unit, abilityId: string): void {
    const ability = getAbilityData(abilityId);
    if (!ability) return;

    const result = executeAbility(attacker, defender, abilityId, this.map!);

    this.notificationRenderer.show(`${attacker.name} used ${ability.name}`);
    this.combatLog.addMessage(`${attacker.name} used ${ability.name}`);
    SoundManager.getInstance().playSound('ability');

    if (ability.type === 'attack') {
      let totalDmg = 0;
      for (let i = 0; i < result.combatResults.length; i++) {
        const combatRes = result.combatResults[i];
        const dmg = combatRes.damage;
        totalDmg += dmg;
        setTimeout(() => {
          this.damagePopups.push({
            x: defender.position.x,
            y: defender.position.y,
            text: dmg > 0 ? `-${dmg}` : 'MISS',
            timer: 1.2,
            color: dmg > 0 ? '#FF4444' : '#AAAAAA',
          });
          if (combatRes.isHit) {
            this.combatLog.addMessage(`Hit ${i + 1}: ${dmg} damage`);
            SoundManager.getInstance().playSound('hit');
            defender.flashTimer = 0.3;
            const dx = defender.position.x - attacker.position.x;
            const dy = defender.position.y - attacker.position.y;
            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
            defender.offsetX = (dx / dist) * 12;
            defender.offsetY = (dy / dist) * 12;
          } else {
            this.combatLog.addMessage(`Hit ${i + 1}: Miss`);
            SoundManager.getInstance().playSound('dodge');
            const dx = defender.position.x - attacker.position.x;
            const dy = defender.position.y - attacker.position.y;
            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
            defender.offsetX = (dx / dist) * -12 + (Math.random() > 0.5 ? 8 : -8);
            defender.offsetY = (dy / dist) * -12 + (Math.random() > 0.5 ? 8 : -8);
          }
        }, i * 300);
      }

      grantAttackXP(attacker);
      if (result.targetDied) {
        grantKillXP(attacker);
        defender.isDying = true;
        if (defender.team === Team.ENEMY) {
          this.combatLog.addMessage(`Enemy ${defender.name} was defeated`);
          this.enemiesDefeatedThisBattle++;
        } else {
          this.combatLog.addMessage(`Ally ${defender.name} fell in combat`);
        }
      }
    } else if (ability.type === 'heal') {
      this.damagePopups.push({
        x: defender.position.x,
        y: defender.position.y,
        text: `+${result.healed}`,
        timer: 1.5,
        color: '#44FF44',
      });
      this.combatLog.addMessage(`${defender.name} recovered ${result.healed} HP`);
      grantAttackXP(attacker);
    }

    if (canLevelUp(attacker)) {
      applyLevelUp(attacker);
      this.combatLog.addMessage(`${attacker.name} leveled up to Lv ${attacker.level}!`);
      this.damagePopups.push({
        x: attacker.position.x,
        y: attacker.position.y,
        text: `LV UP!`,
        timer: 2,
        color: '#FFD700',
      });
    }

    attacker.hasActed = true;
    attacker.flashTimer = 0;
    defender.flashTimer = 0;

    // Proceed as if combat ended
    this.phase = GamePhase.PLAYER_TURN;
    this.checkWinLose();
    this.checkTurnEnd();
  }

  // ─── Death Animations ──────────────────────────────────────────────────────
  private updateDeathAnimations(dt: number): void {
    const dying = this.unitManager.units.filter((u) => u.isDying);
    for (const unit of dying) {
      unit.deathAlpha -= dt / 800;
      if (unit.deathAlpha <= 0) {
        this.unitManager.removeUnit(unit.id);
      }
    }
  }

  private updateUnitOffsets(dt: number): void {
    for (const unit of this.unitManager.units) {
      if (unit.offsetX !== 0) {
        unit.offsetX -= unit.offsetX * (dt / 50);
        if (Math.abs(unit.offsetX) < 0.5) unit.offsetX = 0;
      }
      if (unit.offsetY !== 0) {
        unit.offsetY -= unit.offsetY * (dt / 50);
        if (Math.abs(unit.offsetY) < 0.5) unit.offsetY = 0;
      }
    }
  }

  // ─── Damage Popups ─────────────────────────────────────────────────────────
  private updateDamagePopups(dt: number): void {
    for (const p of this.damagePopups) {
      p.timer -= dt / 1000;
      p.y -= dt * 0.001;
    }
    this.damagePopups = this.damagePopups.filter((p) => p.timer > 0);
  }

  // ─── AI Turn ───────────────────────────────────────────────────────────────
  private updateAITurn(dt: number): void {
    if (this.aiActions.length === 0 && !this.aiMoving && !this.aiWaitingToAttack) {
      this.aiActions = computeAIActions(this.unitManager, this.map!);
      this.aiActionIndex = 0;
      if (this.aiActions.length === 0) {
        this.endEnemyTurn();
        return;
      }
    }

    if (this.aiActionIndex >= this.aiActions.length) {
      this.endEnemyTurn();
      return;
    }

    const action = this.aiActions[this.aiActionIndex];

    if (!this.aiMoving && !this.aiWaitingToAttack) {
      this.aiMoving = true;
      this.aiMovePathIndex = 0;
      this.aiTimer = -600; // Wait 600ms for camera to pan
      if (action.movePath.length > 0) action.unit.isMoving = true;
    }

    this.aiTimer += dt;
    const moveInterval = 1000 / GameConfig.MOVE_SPEED;

    if (this.aiMoving) {
      if (this.aiTimer >= moveInterval && action.movePath.length > 0) {
        this.aiTimer = 0;
        this.aiMovePathIndex++;

        if (this.aiMovePathIndex >= action.movePath.length) {
          action.unit.position = { ...action.targetPosition };
          action.unit.animX = action.targetPosition.x;
          action.unit.animY = action.targetPosition.y;
          action.unit.isMoving = false;
          this.aiMoving = false;
          
          if (action.attackTarget && !action.attackTarget.isDying) {
            this.aiWaitingToAttack = true;
            this.aiTimer = -400; // wait 400ms after moving before attack
          } else {
            action.unit.hasActed = true;
            this.aiActionIndex++;
          }
        } else {
          const pos = action.movePath[this.aiMovePathIndex];
          action.unit.animX = pos.x;
          action.unit.animY = pos.y;
        }
      } else if (this.aiTimer >= 0 && action.movePath.length === 0) {
        // No move needed, go straight to attack if present
        this.aiMoving = false;
        if (action.attackTarget && !action.attackTarget.isDying) {
          this.aiWaitingToAttack = true;
          this.aiTimer = -400;
        } else {
          action.unit.hasActed = true;
          this.aiActionIndex++;
        }
      }
    } else if (this.aiWaitingToAttack && this.aiTimer >= 0) {
      this.startAICombat(action.unit, action.attackTarget!);
      action.unit.hasActed = true;
      this.aiWaitingToAttack = false;
      this.aiActionIndex++;
    }
  }

  private startAICombat(attacker: Unit, defender: Unit): void {
    const result = executeCombat(attacker, defender, this.map!);

    this.damagePopups.push({
      x: defender.position.x,
      y: defender.position.y,
      text: result.damage > 0 ? `-${result.damage}` : 'MISS',
      timer: 1.2,
      color: result.damage > 0 ? '#FF4444' : '#AAAAAA',
    });

    if (result.isCrit) {
      this.combatLog.addMessage(`${attacker.name} rolled 20 -> Critical Hit!`);
    } else if (result.isCritFail) {
      this.combatLog.addMessage(`${attacker.name} rolled 1 -> Critical Fail`);
    } else {
      const hitText = result.isHit ? `Hit` : `Miss`;
      this.combatLog.addMessage(`${attacker.name} rolled ${result.attackRoll} vs CA ${result.targetAC} -> ${hitText}`);
    }

    if (result.isHit) {
      this.combatLog.addMessage(`${attacker.name} dealt ${result.damage} damage`);
      SoundManager.getInstance().playSound('hit');
      defender.flashTimer = 0.3;
      const dx = defender.position.x - attacker.position.x;
      const dy = defender.position.y - attacker.position.y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;
      defender.offsetX = (dx / dist) * 12;
      defender.offsetY = (dy / dist) * 12;
    } else {
      SoundManager.getInstance().playSound('dodge');
      const dx = defender.position.x - attacker.position.x;
      const dy = defender.position.y - attacker.position.y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;
      defender.offsetX = (dx / dist) * -12 + (Math.random() > 0.5 ? 8 : -8);
      defender.offsetY = (dy / dist) * -12 + (Math.random() > 0.5 ? 8 : -8);
    }

    if (result.defenderDied) {
      defender.isDying = true;
      this.combatLog.addMessage(`Ally ${defender.name} fell in combat`);
    }
  }

  private endEnemyTurn(): void {
    this.aiActions = [];
    this.aiActionIndex = 0;
    this.aiMoving = false;
    this.aiWaitingToAttack = false;

    this.unitManager.resetActed(Team.ENEMY);
    
    // MP Regen for enemies
    for (const u of this.unitManager.getTeamUnits(Team.ENEMY)) {
      u.currentMP = Math.min(u.maxMP, u.currentMP + 1);
    }

    this.turnNumber++;
    this.phase = GamePhase.PLAYER_TURN;
    this.unitManager.resetActed(Team.PLAYER);
    
    // MP Regen for players
    for (const u of this.unitManager.getTeamUnits(Team.PLAYER)) {
      u.currentMP = Math.min(u.maxMP, u.currentMP + 1);
    }

    this.processStatusEffects(Team.PLAYER);

    this.hud.showPhaseBanner('PLAYER TURN');

    this.checkWinLose();
  }

  // ─── Turn Logic ────────────────────────────────────────────────────────────
  private checkTurnEnd(): void {
    if (this.unitManager.allActed(Team.PLAYER) && this.phase === GamePhase.PLAYER_TURN) {
      this.startEnemyTurn();
    }
  }

  private startEnemyTurn(): void {
    this.selectedUnit = null;
    this.reachableTiles = [];
    this.attackableTiles = [];
    this.pathPreview = [];
    this.phase = GamePhase.ENEMY_TURN;
    
    this.processStatusEffects(Team.ENEMY);

    this.hud.showPhaseBanner('ENEMY TURN');
  }

  private processStatusEffects(team: Team): void {
    const units = this.unitManager.getTeamUnits(team);
    for (const unit of units) {
      if (unit.isDying) continue;
      
      for (let i = unit.statusEffects.length - 1; i >= 0; i--) {
        const effect = unit.statusEffects[i];
        
        if (effect.onTurnStart === 'dealDamage' && effect.damageDice) {
          const rawDamage = rollDice(effect.damageDice);
          unit.currentHP -= rawDamage;
          
          this.combatLog.addMessage(`${unit.name} takes ${rawDamage} ${effect.name} damage`);
          this.damagePopups.push({
            x: unit.position.x,
            y: unit.position.y,
            text: `-${rawDamage}`,
            timer: 1.5,
            color: effect.effectType === 'poison' ? '#AA00AA' : '#FF0000',
          });
          unit.flashTimer = 0.3;
          
          if (unit.currentHP <= 0) {
            unit.currentHP = 0;
            unit.isDying = true;
            this.combatLog.addMessage(`${unit.name} succumbed to ${effect.name}`);
            if (unit.team === Team.ENEMY) {
               this.enemiesDefeatedThisBattle++;
            }
          }
        } else if (effect.onTurnStart === 'skipTurn') {
          unit.hasActed = true;
          this.combatLog.addMessage(`${unit.name} is ${effect.name.toLowerCase()} and cannot act`);
        }
        
        effect.duration--;
        if (effect.duration <= 0) {
          unit.statusEffects.splice(i, 1);
        }
      }
    }
    this.checkWinLose();
  }

  private checkWinLose(): void {
    const enemies = this.unitManager.getTeamUnits(Team.ENEMY);
    const players = this.unitManager.getTeamUnits(Team.PLAYER);

    if (enemies.length === 0) {
      // Victory
      const reward = this.economy.calculateReward(this.enemiesDefeatedThisBattle);
      this.economy.addGold(reward);
      
      // Handle unit persistence and healing
      const survivors = this.battleManager.processSurvivors(this.unitManager.units);
      this.unitManager.units = survivors; // This effectively removes dead units and heals others

      this.battleResult.show(true, reward, this.enemiesDefeatedThisBattle);
      this.phase = GamePhase.BATTLE_RESULT;
    } else if (players.length === 0) {
      // Defeat
      this.battleResult.show(false, 0, 0);
      this.phase = GamePhase.BATTLE_RESULT;
    }
  }

  // ─── Input ─────────────────────────────────────────────────────────────────
  private setupInput(): void {
    window.addEventListener('keydown', (e) => this.handleInput(e));
  }

  private handleInput(e: KeyboardEvent): void {
    if (this.inputCooldown > 0) return;
    this.inputCooldown = 120; // ms between inputs

    const key = e.key;

    // Battle result screen
    if (this.phase === GamePhase.BATTLE_RESULT) {
      if (key === ' ') {
        this.battleResult.hide();
        if (this.battleResult.victory) {
          this.battleManager.advance(); // Budget increase + Battle number
          this.shopMenu.open();
          this.phase = GamePhase.SHOP;
        } else {
          // Restart to main menu on defeat
          this.startMainMenu();
        }
      }
      return;
    }

    // Main Menu
    if (this.phase === GamePhase.MAIN_MENU || this.phase === GamePhase.SOUND_SETTINGS) {
      this.handleMainMenuInput(key);
      return;
    }

    // Shop
    if (this.phase === GamePhase.SHOP) {
      this.handleShopInput(key);
      return;
    }

    // Menu open
    if (this.phase === GamePhase.MENU_OPEN) {
      this.handleMenuInput(key);
      return;
    }

    // Empty Tile Menu
    if (this.emptyTileMenu.isActive()) {
      this.handleEmptyTileMenuInput(key);
      return;
    }

    // Deployment phase
    if (this.phase === GamePhase.DEPLOYMENT_PHASE) {
      this.handleDeploymentInput(key);
      return;
    }

    // Selecting attack target
    if (this.phase === GamePhase.SELECTING_ATTACK_TARGET) {
      this.handleAttackTargetInput(key);
      return;
    }

    if (this.phase === GamePhase.SELECTING_ABILITY_TARGET) {
      this.handleAbilityTargetInput(key);
      return;
    }

    // Moving
    if (this.phase === GamePhase.MOVING) {
      this.handleMoveInput(key);
      return;
    }

    // Player turn
    if (this.phase === GamePhase.PLAYER_TURN) {
      this.handlePlayerTurnInput(key);
      return;
    }
  }

  private handlePlayerTurnInput(key: string): void {
    if (!this.map) return;
    switch (key) {
      case 'ArrowUp': this.cursor.move(0, -1, this.map.width, this.map.height); break;
      case 'ArrowDown': this.cursor.move(0, 1, this.map.width, this.map.height); break;
      case 'ArrowLeft': this.cursor.move(-1, 0, this.map.width, this.map.height); break;
      case 'ArrowRight': this.cursor.move(1, 0, this.map.width, this.map.height); break;
      case ' ': {
        // Select unit at cursor
        const unit = this.unitManager.getUnitAt(this.cursor.getPosition());
        if (unit) {
          this.enemyInfoPanel.hide(); // Clear existing
          if (unit.team === Team.PLAYER && !unit.hasActed) {
            this.selectedUnit = unit;
            this.isPostMoveAction = false;
            this.unitMenu.open(unit);
            this.unitMenu.options = ['Move', 'Attack', 'Wait'];
             if (unit.abilities.length > 0) {
               this.unitMenu.options.splice(2, 0, 'Ability');
             }
            this.phase = GamePhase.MENU_OPEN;
          } else if (unit.team === Team.ENEMY) {
            this.enemyInfoPanel.show(unit);
          }
        } else {
          // Empty tile - show action menu
          this.emptyTileMenu.open(this.cursor.x, this.cursor.y);
        }
        break;
      }
      case 'Escape': {
        this.enemyInfoPanel.hide();
        break;
      }
    }
  }

  private handleMainMenuInput(key: string): void {
    const isSound = this.phase === GamePhase.SOUND_SETTINGS;
    
    switch (key) {
      case 'ArrowUp': 
        this.mainMenu.moveSelection(-1, isSound); 
        break;
      case 'ArrowDown': 
        this.mainMenu.moveSelection(1, isSound); 
        break;
      case 'ArrowLeft': 
        if (isSound) this.mainMenu.adjustVolume(-10); 
        break;
      case 'ArrowRight': 
        if (isSound) this.mainMenu.adjustVolume(10); 
        break;
      case ' ': {
        const option = this.mainMenu.getSelected(isSound);
        if (isSound) {
          if (option === 'Back') {
            this.phase = GamePhase.MAIN_MENU;
          }
        } else {
          if (option === 'Start Game') {
            if (this.mainMenu.gameMode === 'Random') {
              // Wait for map loading or generation
              this.startNewCampaign();
            } else {
              // Load custom map
              this.loadMap('/maps/map1.json').catch(e => {
                console.error("Failed to load map, falling back to random:", e);
                this.startNewCampaign();
              });
            }
          } else if (option.includes('Game Mode')) {
            this.mainMenu.toggleGameMode();
          } else if (option === 'Sound Settings') {
            this.phase = GamePhase.SOUND_SETTINGS;
            this.mainMenu.reset();
          }
        }
        break;
      }
      case 'Escape': {
        if (isSound) this.phase = GamePhase.MAIN_MENU;
        break;
      }
    }
  }

  private handleMenuInput(key: string): void {
    switch (key) {
      case 'ArrowUp': this.unitMenu.moveSelection(-1); SoundManager.getInstance().playSound('move_cursor'); break;
      case 'ArrowDown': this.unitMenu.moveSelection(1); SoundManager.getInstance().playSound('move_cursor'); break;
      case ' ': {
        const option = this.unitMenu.getSelected();
        this.unitMenu.close();
        SoundManager.getInstance().playSound('select');
        this.executeMenuOption(option);
        break;
      }
      case 'Escape': {
        this.unitMenu.close();
        // If we just moved, mark unit as acted
        if (this.isPostMoveAction && this.selectedUnit) {
          this.selectedUnit.hasActed = true;
        }
        this.selectedUnit = null;
        this.isPostMoveAction = false;
        this.reachableTiles = [];
        this.pathPreview = [];
        this.phase = GamePhase.PLAYER_TURN;
        break;
      }
    }
  }

  private executeMenuOption(option: MenuOption): void {
    if (!this.selectedUnit) return;

    switch (option) {
      case 'Move': {
        if (!this.map) return;
        this.reachableTiles = getReachableTiles(
          this.selectedUnit.position.x,
          this.selectedUnit.position.y,
          this.selectedUnit.movementRange,
          this.map,
          this.unitManager,
          this.selectedUnit.id
        );
        this.phase = GamePhase.MOVING;
        break;
      }
      case 'Attack': {
        // Direct attack from current position
        this.showAttackRange();
        break;
      }
      case 'Ability': {
        this.selectedAbilityId = this.selectedUnit.abilities[0];
        this.showAbilityRange();
        break;
      }
      case 'Wait': {
        this.selectedUnit.hasActed = true;
        this.selectedUnit = null;
        this.isPostMoveAction = false;
        this.phase = GamePhase.PLAYER_TURN;
        this.checkTurnEnd();
        break;
      }
    }
  }

  private handleMoveInput(key: string): void {
    if (!this.map) return;
    switch (key) {
      case 'ArrowUp': this.cursor.move(0, -1, this.map.width, this.map.height); SoundManager.getInstance().playSound('move_cursor'); break;
      case 'ArrowDown': this.cursor.move(0, 1, this.map.width, this.map.height); SoundManager.getInstance().playSound('move_cursor'); break;
      case 'ArrowLeft': this.cursor.move(-1, 0, this.map.width, this.map.height); SoundManager.getInstance().playSound('move_cursor'); break;
      case 'ArrowRight': this.cursor.move(1, 0, this.map.width, this.map.height); SoundManager.getInstance().playSound('move_cursor'); break;
      case ' ': {
        const pos = this.cursor.getPosition();
        const isReachable = this.reachableTiles.some((t) => t.x === pos.x && t.y === pos.y);
        if (isReachable && this.selectedUnit) {
          // Compute and animate path
          const path = findPath(this.selectedUnit.position, pos, this.map, this.unitManager, this.selectedUnit.id);
          if (path.length > 0) {
            this.movePath = path;
            this.movePathIndex = 0;
            this.moveTimer = 0;
            this.selectedUnit.isMoving = true;
            this.reachableTiles = [];
            this.pathPreview = [];
            this.phase = GamePhase.ANIMATION;
          }
        }
        break;
      }
      case 'Escape': {
        this.reachableTiles = [];
        this.pathPreview = [];
        this.selectedUnit = null;
        this.phase = GamePhase.PLAYER_TURN;
        break;
      }
    }

    // Update path preview
    if (this.selectedUnit && this.phase === GamePhase.MOVING && this.map) {
      const pos = this.cursor.getPosition();
      const isReachable = this.reachableTiles.some((t) => t.x === pos.x && t.y === pos.y);
      if (isReachable) {
        this.pathPreview = findPath(this.selectedUnit.position, pos, this.map, this.unitManager, this.selectedUnit.id);
      } else {
        this.pathPreview = [];
      }
    }
  }

  private handleAttackTargetInput(key: string): void {
    switch (key) {
      case 'ArrowUp':
      case 'ArrowDown':
      case 'ArrowLeft':
      case 'ArrowRight': {
        // Cycle through attackable targets
        const curPos = this.cursor.getPosition();
        const curIdx = this.attackableTiles.findIndex((t) => t.x === curPos.x && t.y === curPos.y);
        let newIdx: number;
        if (key === 'ArrowRight' || key === 'ArrowDown') {
          newIdx = (curIdx + 1) % this.attackableTiles.length;
        } else {
          newIdx = (curIdx - 1 + this.attackableTiles.length) % this.attackableTiles.length;
        }
        this.cursor.setPosition(this.attackableTiles[newIdx].x, this.attackableTiles[newIdx].y);
        SoundManager.getInstance().playSound('move_cursor');
        break;
      }
      case ' ': {
        // Attack selected target
        const pos = this.cursor.getPosition();
        const target = this.unitManager.getUnitAt(pos);
        if (target && this.selectedUnit && target.team !== this.selectedUnit.team) {
          this.startCombat(this.selectedUnit, target);
          this.selectedUnit = null;
          this.attackableTiles = [];
        }
        break;
      }
      case 'Escape': {
        // Cancel attack selection
        this.attackableTiles = [];
        if (this.isPostMoveAction && this.selectedUnit) {
          // Re-open action menu
          this.unitMenu.open(this.selectedUnit);
          this.phase = GamePhase.MENU_OPEN;
        } else {
          this.selectedUnit = null;
          this.phase = GamePhase.PLAYER_TURN;
        }
        break;
      }
    }
  }

  private handleAbilityTargetInput(key: string): void {
    switch (key) {
      case 'ArrowUp':
      case 'ArrowDown':
      case 'ArrowLeft':
      case 'ArrowRight': {
        const curPos = this.cursor.getPosition();
        const curIdx = this.attackableTiles.findIndex((t) => t.x === curPos.x && t.y === curPos.y);
        let newIdx: number;
        if (key === 'ArrowRight' || key === 'ArrowDown') {
          newIdx = (curIdx + 1) % this.attackableTiles.length;
        } else {
          newIdx = (curIdx - 1 + this.attackableTiles.length) % this.attackableTiles.length;
        }
        this.cursor.setPosition(this.attackableTiles[newIdx].x, this.attackableTiles[newIdx].y);
        SoundManager.getInstance().playSound('move_cursor');
        break;
      }
      case ' ': {
        const pos = this.cursor.getPosition();
        const target = this.unitManager.getUnitAt(pos);
        if (target && this.selectedUnit && this.selectedAbilityId) {
          // Play flash animation
          this.selectedUnit.flashTimer = 0.3;
          target.flashTimer = 0.3;
          this.phase = GamePhase.ANIMATION; // Prevent input temporarily while animating hits
          this.finalizeAbility(this.selectedUnit, target, this.selectedAbilityId);
          this.selectedUnit = null;
          this.selectedAbilityId = null;
          this.attackableTiles = [];
        }
        break;
      }
      case 'Escape': {
        this.attackableTiles = [];
        this.selectedAbilityId = null;
        if (this.isPostMoveAction && this.selectedUnit) {
          this.unitMenu.open(this.selectedUnit);
          this.phase = GamePhase.MENU_OPEN;
        } else {
          this.selectedUnit = null;
          this.phase = GamePhase.PLAYER_TURN;
        }
        break;
      }
    }
  }

  private handleShopInput(key: string): void {
    switch (key) {
      case 'ArrowUp': this.shopMenu.moveSelection(-1); SoundManager.getInstance().playSound('move_cursor'); break;
      case 'ArrowDown': this.shopMenu.moveSelection(1); SoundManager.getInstance().playSound('move_cursor'); break;
      case ' ': {
        const item = this.shopMenu.getSelected();
        if (this.economy.spend(item.cost)) {
          // Add unit to player team (spawn near first player unit or map start)
          SoundManager.getInstance().playSound('shop_buy');
          const spawn = this.findFreeSpawn();
          const newUnit = createUnit(item.id, Team.PLAYER, spawn);
          this.unitManager.addUnit(newUnit);
          this.shopMenu.showMessage(`Recruited ${item.name}!`);
        } else {
          this.shopMenu.showMessage('Not enough gold!');
        }
        break;
      }
      case 'Escape': {
        this.shopMenu.close();
        if (this.unitManager.getTeamUnits(Team.PLAYER).length === 0) {
           this.shopMenu.showMessage("Recruit at least one unit!");
           this.shopMenu.open();
           return;
        }
        // Advance campaign and start new battle
        // If it's not the first battle, advance budget
        if (this.battleManager.currentBattleNumber > 1 || this.enemiesDefeatedThisBattle > 0) {
           // We only advance after first shop or subsequent victories
           // Actually advance() should be called here or at victory. 
           // Let's call it here if we just finished a battle.
        }
        this.generateNewMap();
        break;
      }
    }
  }

  private findFreeSpawn(): Position {
    // If map not loaded yet (e.g., in shop), return a placeholder position
    if (!this.map) {
      return { x: 0, y: 0 };
    }
    
    // Find unoccupied spawn point
    for (const sp of this.map.playerSpawns) {
      if (!this.unitManager.isOccupied(sp.x, sp.y)) return sp;
    }
    // Fallback: find any empty grass near origin
    for (let y = 0; y < this.map.height; y++) {
      for (let x = 0; x < this.map.width; x++) {
        if (this.map.isPassable(x, y) && !this.unitManager.isOccupied(x, y)) {
          return { x, y };
        }
      }
    }
    return { x: 0, y: 0 };
  }

  private handleDeploymentInput(key: string): void {
    if (!this.map) return;
    switch (key) {
      case 'ArrowUp': this.cursor.move(0, -1, this.map.width, this.map.height); break;
      case 'ArrowDown': this.cursor.move(0, 1, this.map.width, this.map.height); break;
      case 'ArrowLeft': this.cursor.move(-1, 0, this.map.width, this.map.height); break;
      case 'ArrowRight': this.cursor.move(1, 0, this.map.width, this.map.height); break;
      case ' ': {
        // Select unit at cursor to move
        const unit = this.unitManager.getUnitAt(this.cursor.getPosition());
        if (unit && unit.team === Team.PLAYER && this.deploymentSystem.getUnitPosition(unit)) {
          this.selectedUnit = unit;
          this.unitMenu.open(unit);
          this.unitMenu.options = ['Reposition'];
          this.phase = GamePhase.MENU_OPEN;
        }
        break;
      }
      case 'Enter': {
        // Finish deployment and start battle
        this.phase = GamePhase.PLAYER_TURN;
        this.hud.showPhaseBanner(`BATTLE ${this.battleManager.currentBattleNumber} - PLAYER TURN`);
        this.combatLog.addMessage('Deployment complete. Battle start!');
        break;
      }
      case 'Escape': {
        // Cancel and go back to shop
        this.phase = GamePhase.SHOP;
        this.shopMenu.open();
        break;
      }
    }
  }

  private handleEmptyTileMenuInput(key: string): void {
    switch (key) {
      case 'ArrowUp': 
        this.emptyTileMenu.moveSelection(-1); 
        SoundManager.getInstance().playSound('move_cursor'); 
        break;
      case 'ArrowDown': 
        this.emptyTileMenu.moveSelection(1); 
        SoundManager.getInstance().playSound('move_cursor'); 
        break;
      case ' ': {
        const option = this.emptyTileMenu.getSelectedOption();
        this.emptyTileMenu.close();
        
        switch (option) {
          case 'Pass Turn': {
            // All remaining player units skip their turn
            for (const unit of this.unitManager.getTeamUnits(Team.PLAYER)) {
              unit.hasActed = true;
            }
            this.phase = GamePhase.ENEMY_TURN;
            this.hud.showPhaseBanner('ENEMY TURN');
            this.aiActions = computeAIActions(this.unitManager, this.map!);
            this.aiActionIndex = 0;
            break;
          }
          case 'Save Game': {
            // TODO: Implement save game
            this.combatLog.addMessage('Game saved!');
            SoundManager.getInstance().playSound('menu_confirm');
            break;
          }
          case 'Load Game': {
            // TODO: Implement load game
            this.combatLog.addMessage('Load feature - not yet implemented');
            break;
          }
          case 'Exit to Menu': {
            this.phase = GamePhase.MAIN_MENU;
            this.mainMenu.reset();
            break;
          }
        }
        break;
      }
      case 'Escape': {
        this.emptyTileMenu.close();
        break;
      }
    }
  }

  // ─── Render ────────────────────────────────────────────────────────────────
  private render(time: number): void {
    const ctx = this.ctx;
    const cw = GameConfig.CANVAS_WIDTH;
    const ch = GameConfig.CANVAS_HEIGHT;

    // Clear
    ctx.fillStyle = '#111';
    ctx.fillRect(0, 0, cw, ch);

    if (this.phase === GamePhase.MAIN_MENU || this.phase === GamePhase.SOUND_SETTINGS) {
      this.mainMenu.render(ctx, this.phase === GamePhase.SOUND_SETTINGS);
      return; // Skip rendering game world
    }

    // If no map loaded yet (e.g., in shop phase before first battle), render shop and return
    if (!this.map) {
      this.shopMenu.render(ctx, this.economy);
      return;
    }

    // Camera target determination
    if (this.map) {
      if (this.phase === GamePhase.ENEMY_TURN && this.aiActions.length > 0 && this.aiActionIndex < this.aiActions.length) {
        const action = this.aiActions[this.aiActionIndex];
        if (this.aiWaitingToAttack && action.attackTarget) {
          this.camera.follow(action.attackTarget.position.x, action.attackTarget.position.y, this.map.width, this.map.height);
        } else {
          // Fallback to animX/animY for smooth follow during movement calculation
          this.camera.follow(action.unit.animX, action.unit.animY, this.map.width, this.map.height);
        }
      } else {
        this.camera.follow(this.cursor.x, this.cursor.y, this.map.width, this.map.height);
      }
    }

    const camX = this.camera.x;
    const camY = this.camera.y;

    // Get layout dimensions
    const shopX = this.layoutManager.getShopPanelBounds().x;
    const mapViewport = this.layoutManager.getMapViewportBounds();
    const combatLogX = this.layoutManager.getCombatLogBounds().x;

    // Left Panel: Shop
    ctx.save();
    ctx.beginPath();
    ctx.rect(shopX, 0, GameConfig.SHOP_PANEL_WIDTH, ch);
    ctx.clip();
    this.shopMenu.render(ctx, this.economy);
    ctx.restore();

    // Center Panel: Map
    ctx.save();
    ctx.beginPath();
    ctx.rect(mapViewport.x, mapViewport.y, mapViewport.width, mapViewport.height);
    ctx.clip();

    // Map
    if (this.map) this.mapRenderer.render(this.map, camX, camY);

    // Deployment zone highlights
    if (this.phase === GamePhase.DEPLOYMENT_PHASE) {
      const deploymentTiles = this.deploymentSystem.getDeploymentTiles();
      this.mapRenderer.renderHighlights(deploymentTiles, GameConfig.COLORS.DEPLOYMENT_AREA, camX, camY);
    }

    // Highlights
    if (this.reachableTiles.length > 0) {
      this.mapRenderer.renderHighlights(this.reachableTiles, GameConfig.COLORS.MOVE_HIGHLIGHT, camX, camY);
    }
    if (this.attackableTiles.length > 0) {
      this.mapRenderer.renderHighlights(this.attackableTiles, GameConfig.COLORS.ATTACK_HIGHLIGHT, camX, camY);
    }

    // Path preview
    if (this.pathPreview.length > 1) {
      this.mapRenderer.renderPath(this.pathPreview, camX, camY);
    }

    // Units
    this.unitRenderer.render(this.unitManager.units, camX, camY, time);

    // Cursor
    this.cursor.render(ctx, camX, camY);

    // Damage popups
    this.renderDamagePopups(camX, camY);

    ctx.restore();

    // Right Panel: Combat Log
    ctx.save();
    ctx.beginPath();
    ctx.rect(combatLogX, 0, GameConfig.COMBAT_LOG_PANEL_WIDTH, ch);
    ctx.clip();
    this.combatLog.render(ctx, time);
    ctx.restore();

    // HUD (overlays all panels)
    this.hud.render(
      this.phase,
      this.turnNumber,
      this.economy,
      this.unitManager,
      this.cursor.x,
      this.cursor.y,
      this.map,
      this.battleManager.currentBattleNumber
    );

    // Draw dividers
    this.layoutManager.renderDividers(ctx);

    // Notifications
    this.notificationRenderer.render(ctx);

    // Enemy Info
    this.enemyInfoPanel.render(ctx);

    // Unit menu
    this.unitMenu.render(ctx);

    // Empty Tile Menu
    this.emptyTileMenu.render(ctx);

    // Battle result
    this.battleResult.render(ctx);
  }

  private renderDamagePopups(camX: number, camY: number): void {
    const ts = GameConfig.TILE_SIZE;
    for (const p of this.damagePopups) {
      const sx = p.x * ts + ts / 2 - camX;
      const sy = p.y * ts - camY - 10;
      this.ctx.save();
      this.ctx.globalAlpha = Math.min(1, p.timer);
      this.ctx.fillStyle = p.color;
      this.ctx.font = 'bold 20px monospace';
      this.ctx.textAlign = 'center';
      this.ctx.fillText(p.text, sx, sy);
      this.ctx.restore();
    }
  }
}
