import { Unit } from '../core/Types.ts';
import { GameConfig } from '../config/GameConfig.ts';
import { SpriteManager } from '../render/SpriteManager.ts';

// ─── Unit Menu (Move / Attack / Ability / Wait) ──────────────────────────────

export type MenuOption = 'Move' | 'Attack' | 'Ability' | 'Wait' | 'Reposition';

export class UnitMenu {
  visible: boolean = false;
  unit: Unit | null = null;
  options: MenuOption[] = ['Move', 'Attack', 'Ability', 'Wait'];
  selectedIndex: number = 0;

  open(unit: Unit): void {
    this.unit = unit;
    this.visible = true;
    this.selectedIndex = 0;
  }

  close(): void {
    this.visible = false;
    this.unit = null;
    this.selectedIndex = 0;
  }

  moveSelection(dir: number): void {
    this.selectedIndex = Math.max(0, Math.min(this.options.length - 1, this.selectedIndex + dir));
  }

  getSelected(): MenuOption {
    return this.options[this.selectedIndex];
  }

  render(ctx: CanvasRenderingContext2D): void {
    if (!this.visible || !this.unit) return;

    const cw = GameConfig.CANVAS_WIDTH;
    const ch = GameConfig.CANVAS_HEIGHT;

    // Darkened overlay
    ctx.fillStyle = GameConfig.COLORS.MENU_OVERLAY;
    ctx.fillRect(0, 0, cw, ch);

    // Portrait rendered outside and to the left
    const sm = SpriteManager.getInstance();
    const portrait = sm.getSprite(`${this.unit.className}_portrait`);
    
    const portraitX = 140;
    const portraitY = ch / 2;
    const portraitSize = 240;

    if (portrait) {
      // Draw big portrait on the left side
      ctx.drawImage(portrait, portraitX - portraitSize / 2, portraitY - portraitSize / 2, portraitSize, portraitSize);
    } else {
      // Fallback: draw colored circle
      ctx.fillStyle = this.unit.color;
      ctx.beginPath();
      ctx.arc(portraitX, portraitY, 100, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = '#FFFFFF';
      ctx.lineWidth = 3;
      ctx.stroke();
    }

    // Unit name below portrait (outside panel)
    ctx.fillStyle = '#FFFFFF';
    ctx.font = 'bold 20px monospace';
    ctx.textAlign = 'center';
    ctx.fillText(this.unit.name, portraitX, portraitY + 140);

    // Menu panel (now smaller, positioned to the right)
    const panelW = 380;
    const panelH = 340;
    const panelX = portraitX + 180;
    const panelY = (ch - panelH) / 2;

    // Panel background
    ctx.fillStyle = 'rgba(20, 25, 40, 0.98)';
    ctx.strokeStyle = '#5577AA';
    ctx.lineWidth = 2;
    this.roundRect(ctx, panelX, panelY, panelW, panelH, 12);
    ctx.fill();
    ctx.stroke();

    // ─── Stats & Options in Menu ────────────────────────────────────────────
    const rightMargin = 25;
    const contentW = panelW - rightMargin * 2;
    const centerX = panelX + panelW / 2;

    // HP bar
    const hpBarW = contentW;
    const hpBarH = 14;
    const hpBarX = panelX + rightMargin;
    const hpBarY = panelY + 30;
    const hpRatio = this.unit.currentHP / this.unit.maxHP;

    ctx.fillStyle = GameConfig.COLORS.HP_BAR_BG;
    this.roundRect(ctx, hpBarX, hpBarY, hpBarW, hpBarH, 4);
    ctx.fill();

    ctx.fillStyle = hpRatio > 0.35 ? GameConfig.COLORS.HP_BAR_FILL : GameConfig.COLORS.HP_BAR_LOW;
    this.roundRect(ctx, hpBarX, hpBarY, hpBarW * hpRatio, hpBarH, 4);
    ctx.fill();

    ctx.fillStyle = '#FFFFFF';
    ctx.font = 'bold 14px monospace';
    ctx.textAlign = 'center';
    ctx.fillText(
      `HP: ${this.unit.currentHP} / ${this.unit.maxHP}`,
      centerX,
      hpBarY + hpBarH + 18
    );

    // Stats Grid
    const statsStartY = hpBarY + 50;
    ctx.fillStyle = '#AABBCC';
    ctx.font = '13px monospace';
    ctx.textAlign = 'left';
    
    ctx.fillText(`ATK: ${this.unit.damageDice}`, panelX + rightMargin, statsStartY);
    ctx.fillText(`CA:  ${10 + this.unit.defense}`, panelX + rightMargin + 80, statsStartY);
    
    ctx.fillText(`DEF: ${this.unit.defense}`, panelX + rightMargin, statsStartY + 22);
    ctx.fillText(`MOV: ${this.unit.movementRange}`, panelX + rightMargin + 80, statsStartY + 22);
    
    ctx.fillText(`RNG: ${this.unit.attackRange}`, panelX + rightMargin, statsStartY + 44);
    ctx.fillText(`MP:  ${this.unit.currentMP}/${this.unit.maxMP}`, panelX + rightMargin + 80, statsStartY + 44);

    // Options
    const optStartY = statsStartY + 70;
    for (let i = 0; i < this.options.length; i++) {
      const oy = optStartY + i * 32;
      const isSelected = i === this.selectedIndex;
      const isDisabled = this.options[i] === 'Ability' && this.unit.abilities.length === 0;

      if (isSelected && !isDisabled) {
        ctx.fillStyle = 'rgba(80, 130, 220, 0.4)';
        this.roundRect(ctx, panelX + rightMargin - 8, oy - 12, contentW + 16, 28, 6);
        ctx.fill();
        ctx.strokeStyle = '#88AAFF';
        ctx.lineWidth = 1;
        ctx.stroke();
      } else if (isSelected && isDisabled) {
        ctx.fillStyle = 'rgba(100, 100, 100, 0.4)';
        this.roundRect(ctx, panelX + rightMargin - 8, oy - 12, contentW + 16, 28, 6);
        ctx.fill();
      }

      if (isDisabled) {
        ctx.fillStyle = '#666666';
      } else {
        ctx.fillStyle = isSelected ? '#FFFFFF' : '#8899AA';
      }
      
      ctx.font = isSelected ? 'bold 16px monospace' : '16px monospace';
      ctx.textAlign = 'center';
      ctx.fillText(this.options[i], centerX, oy + 6);
    }
  }

  private roundRect(
    ctx: CanvasRenderingContext2D,
    x: number,
    y: number,
    w: number,
    h: number,
    r: number
  ): void {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  }
}
