import { GameConfig } from '../config/GameConfig.ts';

// ─── Camera ──────────────────────────────────────────────────────────────────
export class Camera {
  x: number = 0;
  y: number = 0;

  follow(tileX: number, tileY: number, mapWidth: number, mapHeight: number): void {
    const ts = GameConfig.TILE_SIZE;
    const targetX = tileX * ts - GameConfig.CANVAS_WIDTH / 2 + ts / 2;
    const targetY = tileY * ts - GameConfig.CANVAS_HEIGHT / 2 + ts / 2;

    const maxX = mapWidth * ts - GameConfig.CANVAS_WIDTH;
    const maxY = mapHeight * ts - GameConfig.CANVAS_HEIGHT;

    // Smooth lerp
    this.x += (Math.max(0, Math.min(maxX, targetX)) - this.x) * 0.15;
    this.y += (Math.max(0, Math.min(maxY, targetY)) - this.y) * 0.15;
  }
}
