import { GameConfig } from '../config/GameConfig.ts';

/**
 * Manages the 3-panel layout: Shop (left) | Map (center) | Combat Log (right)
 */
export class LayoutManager {
  readonly shopPanelX: number = 0;
  readonly shopPanelWidth: number = GameConfig.SHOP_PANEL_WIDTH;

  readonly mapCenterX: number = GameConfig.SHOP_PANEL_WIDTH;
  readonly mapCenterWidth: number = GameConfig.CANVAS_WIDTH - GameConfig.SHOP_PANEL_WIDTH - GameConfig.COMBAT_LOG_PANEL_WIDTH;

  readonly combatLogX: number = GameConfig.SHOP_PANEL_WIDTH + this.mapCenterWidth;
  readonly combatLogWidth: number = GameConfig.COMBAT_LOG_PANEL_WIDTH;

  readonly panelHeight: number = GameConfig.CANVAS_HEIGHT;

  // Render vertical separators between panels
  renderDividers(ctx: CanvasRenderingContext2D): void {
    ctx.strokeStyle = 'rgba(100, 100, 120, 0.5)';
    ctx.lineWidth = 2;

    // Left separator (between shop and map)
    ctx.beginPath();
    ctx.moveTo(this.mapCenterX, 0);
    ctx.lineTo(this.mapCenterX, this.panelHeight);
    ctx.stroke();

    // Right separator (between map and combat log)
    ctx.beginPath();
    ctx.moveTo(this.combatLogX, 0);
    ctx.lineTo(this.combatLogX, this.panelHeight);
    ctx.stroke();
  }

  // Get map camera offset to account for the left panel
  getMapViewportOffsetX(): number {
    return this.mapCenterX;
  }

  // Get effective map viewport dimensions
  getMapViewportWidth(): number {
    return this.mapCenterWidth;
  }

  getMapViewportHeight(): number {
    return this.panelHeight;
  }

  // Get panel boundary rectangles
  getShopPanelBounds(): { x: number; y: number; width: number; height: number } {
    return {
      x: this.shopPanelX,
      y: 0,
      width: this.shopPanelWidth,
      height: this.panelHeight,
    };
  }

  getMapViewportBounds(): { x: number; y: number; width: number; height: number } {
    return {
      x: this.mapCenterX,
      y: 0,
      width: this.mapCenterWidth,
      height: this.panelHeight,
    };
  }

  getCombatLogBounds(): { x: number; y: number; width: number; height: number } {
    return {
      x: this.combatLogX,
      y: 0,
      width: this.combatLogWidth,
      height: this.panelHeight,
    };
  }
}
