import { MapData, Position } from '../core/Types.ts';
import { GameConfig } from '../config/GameConfig.ts';

/**
 * Generates a random map with structured terrain (grouped forests/rocks, connected water).
 * Uses cellular automata or simple grouping, and validates path connectivity.
 */
export class MapGenerator {
  static generate(width?: number, height?: number): MapData {
    // Use provided dimensions or randomize within configured ranges
    const finalWidth = width || this.randomInt(GameConfig.MAP_MIN_WIDTH, GameConfig.MAP_MAX_WIDTH);
    const finalHeight = height || this.randomInt(GameConfig.MAP_MIN_HEIGHT, GameConfig.MAP_MAX_HEIGHT);
    
    let terrain: string[][] = [];
    let isValid = false;
    let playerSpawns: Position[] = [];
    let enemySpawns: Position[] = [];
    let attempts = 0;
    const maxAttempts = 50; // Prevent infinite loops

    // Keep generating until we have a valid map where player and enemy spawns are connected
    while (!isValid && attempts < maxAttempts) {
      attempts++;
      terrain = this.generateBaseTerrain(finalWidth, finalHeight);
      
      // Carve out spawn areas to ensure they are empty (grass)
      this.carveSpawnAreas(terrain, finalWidth, finalHeight);
      
      playerSpawns = [
        { x: 1, y: 1 }, { x: 2, y: 1 }, { x: 1, y: 2 }, { x: 2, y: 2 }, { x: 3, y: 1 }
      ];
      enemySpawns = [
        { x: finalWidth - 2, y: finalHeight - 2 }, { x: finalWidth - 3, y: finalHeight - 2 }, 
        { x: finalWidth - 2, y: finalHeight - 3 }, { x: finalWidth - 3, y: finalHeight - 3 }, { x: finalWidth - 4, y: finalHeight - 2 }
      ];

      isValid = this.checkConnectivity(terrain, finalWidth, finalHeight, playerSpawns[0], enemySpawns[0]);
    }

    // If we couldn't find a valid map after max attempts, return what we have
    return {
      width: finalWidth,
      height: finalHeight,
      terrain,
      playerSpawns,
      enemySpawns,
    };
  }

  private static randomInt(min: number, max: number): number {
    return Math.floor(Math.random() * (max - min + 1)) + min;
  }

  private static generateBaseTerrain(width: number, height: number): string[][] {
    const terrain: string[][] = Array.from({ length: height }, () => Array(width).fill('grass'));

    // Scale clusters based on map size - increased spawn rates for water/rock
    const mapArea = width * height;
    const forestClusters = Math.max(2, Math.floor(mapArea / 85));
    const rockClusters = Math.max(2, Math.floor(mapArea / 100));  // Increased from 120
    const waterClusters = Math.max(2, Math.floor(mapArea / 120)); // Increased from 150

    this.spawnClusters(terrain, width, height, 'forest', forestClusters, 5, 15);
    this.spawnClusters(terrain, width, height, 'rock', rockClusters, 4, 10);
    this.spawnClusters(terrain, width, height, 'water', waterClusters, 6, 18);

    return terrain;
  }

  private static spawnClusters(
    terrain: string[][], 
    width: number, 
    height: number, 
    type: string, 
    count: number, 
    minSize: number, 
    maxSize: number
  ) {
    for (let c = 0; c < count; c++) {
      // Random starting point
      let startX = Math.floor(Math.random() * width);
      let startY = Math.floor(Math.random() * height);
      
      // Don't spawn on occupied tiles or too close to edges
      if (startX < 1) startX = 1;
      if (startY < 1) startY = 1;
      if (startX >= width - 1) startX = width - 2;
      if (startY >= height - 1) startY = height - 2;

      const targetSize = minSize + Math.floor(Math.random() * (maxSize - minSize));
      const queue: { x: number; y: number }[] = [{ x: startX, y: startY }];
      const placed = new Set<string>();
      placed.add(`${startX},${startY}`);
      
      if (terrain[startY][startX] === 'grass') {
        terrain[startY][startX] = type;
      }

      // Expand cluster using random walk BFS
      let noProgressCount = 0;
      while (queue.length > 0 && placed.size < targetSize && noProgressCount < 20) {
        // Randomly pick from queue to keep growth organic
        const idx = Math.floor(Math.random() * queue.length);
        const { x, y } = queue[idx];
        const placedSizeBefore = placed.size;

        // Try multiple directions before giving up
        for (let attempt = 0; attempt < 4 && placed.size < targetSize; attempt++) {
          const dirs = [
            { dx: 0, dy: -1 }, { dx: 1, dy: 0 }, 
            { dx: 0, dy: 1 }, { dx: -1, dy: 0 }
          ];
          const dir = dirs[Math.floor(Math.random() * dirs.length)];
          
          const nx = x + dir.dx;
          const ny = y + dir.dy;
          const key = `${nx},${ny}`;

          // Within bounds and not already visited
          if (nx > 0 && nx < width - 1 && ny > 0 && ny < height - 1 && !placed.has(key)) {
            placed.add(key);
            if (terrain[ny][nx] === 'grass') {
              terrain[ny][nx] = type;
              queue.push({ x: nx, y: ny });
            }
          }
        }

        // Track progress - if no new tiles added, increment no-progress counter
        if (placed.size === placedSizeBefore) {
          noProgressCount++;
        } else {
          noProgressCount = 0;
        }

        // Remove head of queue if it gets too large
        if (queue.length > 15) queue.shift();
      }
    }
  }

  private static carveSpawnAreas(terrain: string[][], width: number, height: number) {
    // Top-left area (Player)
    for (let y = 0; y < Math.min(4, height); y++) {
      for (let x = 0; x < Math.min(4, width); x++) {
        terrain[y][x] = 'grass';
      }
    }
    // Bottom-right area (Enemy)
    for (let y = Math.max(0, height - 4); y < height; y++) {
      for (let x = Math.max(0, width - 4); x < width; x++) {
        terrain[y][x] = 'grass';
      }
    }
  }

  private static checkConnectivity(terrain: string[][], width: number, height: number, start: Position, goal: Position): boolean {
    const queue: Position[] = [start];
    const visited = new Set<string>();
    visited.add(`${start.x},${start.y}`);

    const dirs = [{ x: 0, y: -1 }, { x: 1, y: 0 }, { x: 0, y: 1 }, { x: -1, y: 0 }];

    while (queue.length > 0) {
      const { x, y } = queue.shift()!;

      if (x === goal.x && y === goal.y) return true;

      for (const d of dirs) {
        const nx = x + d.x;
        const ny = y + d.y;

        if (nx >= 0 && nx < width && ny >= 0 && ny < height) {
          // Rock and Water are impassable
          if (terrain[ny][nx] !== 'rock' && terrain[ny][nx] !== 'water') {
            const key = `${nx},${ny}`;
            if (!visited.has(key)) {
              visited.add(key);
              queue.push({ x: nx, y: ny });
            }
          }
        }
      }
    }

    return false;
  }
}
