import { GameConfig } from '../config/GameConfig.ts';
import { Unit } from '../core/Types.ts';

/**
 * UI Panel to display enemy unit statistics when clicked.
 */
export class EnemyInfoPanel {
  visible: boolean = false;
  unit: Unit | null = null;

  show(unit: Unit): void {
    this.unit = unit;
    this.visible = true;
  }

  hide(): void {
    this.visible = false;
    this.unit = null;
  }

  render(ctx: CanvasRenderingContext2D): void {
    if (!this.visible || !this.unit) return;

    const cw = GameConfig.CANVAS_WIDTH;
    const ch = GameConfig.CANVAS_HEIGHT;

    const panelW = 220;
    const panelH = 140;
    const padding = 16;
    const panelX = cw - panelW - padding;
    const panelY = padding + 40; // Below HUD

    // Panel background
    ctx.fillStyle = 'rgba(40, 15, 15, 0.9)';
    ctx.strokeStyle = '#AA4444';
    ctx.lineWidth = 2;
    
    ctx.beginPath();
    ctx.roundRect(panelX, panelY, panelW, panelH, 8);
    ctx.fill();
    ctx.stroke();

    // Unit Name & Class
    ctx.fillStyle = '#FFFFFF';
    ctx.font = 'bold 16px monospace';
    ctx.textAlign = 'left';
    ctx.fillText(`Enemy ${this.unit.name}`, panelX + 16, panelY + 24);

    ctx.fillStyle = '#AAAAAA';
    ctx.font = '12px monospace';
    ctx.fillText(`Lv ${this.unit.level} ${this.unit.className}`, panelX + 16, panelY + 40);

    // HP Bar
    const hpY = panelY + 54;
    const hpRatio = this.unit.currentHP / this.unit.maxHP;
    ctx.fillStyle = '#333';
    ctx.fillRect(panelX + 16, hpY, panelW - 32, 10);
    ctx.fillStyle = hpRatio > 0.3 ? '#44DD44' : '#DD4444';
    ctx.fillRect(panelX + 16, hpY, (panelW - 32) * hpRatio, 10);
    
    ctx.fillStyle = '#FFFFFF';
    ctx.textAlign = 'right';
    ctx.fillText(`${this.unit.currentHP}/${this.unit.maxHP}`, panelX + panelW - 16, hpY - 4);

    // Stats
    const statsY = hpY + 24;
    ctx.textAlign = 'left';
    ctx.fillStyle = '#FFDDDD';
    ctx.fillText(`ATK: ${this.unit.damageDice}`, panelX + 16, statsY);
    ctx.fillText(`CA: ${10 + this.unit.defense}`, panelX + 110, statsY);
    
    ctx.fillText(`DEF: ${this.unit.defense}`, panelX + 16, statsY + 18);
    ctx.fillText(`MOV: ${this.unit.movementRange}`, panelX + 110, statsY + 18);
    
    ctx.fillText(`RNG: ${this.unit.attackRange}`, panelX + 16, statsY + 36);

    // Prompt to close
    ctx.fillStyle = '#777777';
    ctx.font = '10px monospace';
    ctx.textAlign = 'center';
    ctx.fillText('Press ESC or Click elsewhere to close', panelX + panelW / 2, panelY + panelH - 12);
  }
}
