import { Unit, Position } from '../core/Types.ts';
import { GameConfig } from '../config/GameConfig.ts';

/**
 * Manages the deployment phase where the player positions units before battle
 */
export class DeploymentSystem {
  private deploymentColumns: number = GameConfig.DEPLOYMENT_COLUMNS;
  private validDeploymentTiles: Position[] = [];
  private unitPositions: Map<Unit, Position> = new Map();

  /**
   * Initialize deployment zones for a given map size
   */
  initializeDeploymentZones(mapWidth: number, mapHeight: number): void {
    this.validDeploymentTiles = [];
    // First N columns are deployment zone
    for (let y = 0; y < mapHeight; y++) {
      for (let x = 0; x < this.deploymentColumns; x++) {
        this.validDeploymentTiles.push({ x, y });
      }
    }
  }

  /**
   * Check if a tile is a valid deployment position
   */
  isValidDeploymentTile(x: number, y: number): boolean {
    return this.validDeploymentTiles.some(t => t.x === x && t.y === y);
  }

  /**
   * Get all valid deployment tiles
   */
  getDeploymentTiles(): Position[] {
    return [...this.validDeploymentTiles];
  }

  /**
   * Place a unit at a deployment position
   */
  placeUnit(unit: Unit, x: number, y: number): boolean {
    if (!this.isValidDeploymentTile(x, y)) {
      return false;
    }
    this.unitPositions.set(unit, { x, y });
    return true;
  }

  /**
   * Get the deployment position of a unit
   */
  getUnitPosition(unit: Unit): Position | undefined {
    return this.unitPositions.get(unit);
  }

  /**
   * Move a unit to a new deployment position
   */
  moveUnit(unit: Unit, x: number, y: number): boolean {
    if (!this.isValidDeploymentTile(x, y)) {
      return false;
    }
    // Check if another unit is already there
    for (const [u, pos] of this.unitPositions) {
      if (u !== unit && pos.x === x && pos.y === y) {
        return false; // Occupied
      }
    }
    this.unitPositions.set(unit, { x, y });
    return true;
  }

  /**
   * Get all positioned units
   */
  getPositionedUnits(): Map<Unit, Position> {
    return new Map(this.unitPositions);
  }

  /**
   * Clear all deployment data
   */
  clear(): void {
    this.validDeploymentTiles = [];
    this.unitPositions.clear();
  }
}
