import { GameConfig } from '../config/GameConfig.ts';

export type EmptyTileMenuOption = 'Pass Turn' | 'Save Game' | 'Load Game' | 'Exit to Menu';

export class EmptyTileMenu {
  private isOpen: boolean = false;
  private options: EmptyTileMenuOption[] = ['Pass Turn', 'Save Game', 'Load Game', 'Exit to Menu'];
  private selectedIndex: number = 0;
  private x: number = 0;
  private y: number = 0;

  open(x: number, y: number): void {
    this.isOpen = true;
    this.selectedIndex = 0;
    this.x = x;
    this.y = y;
  }

  close(): void {
    this.isOpen = false;
  }

  isActive(): boolean {
    return this.isOpen;
  }

  moveSelection(direction: number): void {
    this.selectedIndex += direction;
    if (this.selectedIndex < 0) this.selectedIndex = this.options.length - 1;
    if (this.selectedIndex >= this.options.length) this.selectedIndex = 0;
  }

  getSelectedOption(): EmptyTileMenuOption {
    return this.options[this.selectedIndex];
  }

  render(ctx: CanvasRenderingContext2D): void {
    if (!this.isOpen) return;

    const menuWidth = 160;
    const itemHeight = 30;
    const menuHeight = this.options.length * itemHeight + 10;

    // Position menu near cursor or center
    let menuX = this.x * GameConfig.TILE_SIZE + 20;
    let menuY = this.y * GameConfig.TILE_SIZE + 20;

    // Keep menu on screen
    if (menuX + menuWidth > GameConfig.CANVAS_WIDTH) menuX = GameConfig.CANVAS_WIDTH - menuWidth - 10;
    if (menuY + menuHeight > GameConfig.CANVAS_HEIGHT) menuY = GameConfig.CANVAS_HEIGHT - menuHeight - 10;

    // Semi-transparent background
    ctx.fillStyle = 'rgba(30, 30, 40, 0.95)';
    ctx.fillRect(menuX, menuY, menuWidth, menuHeight);

    // Border
    ctx.strokeStyle = 'rgba(100, 150, 200, 0.8)';
    ctx.lineWidth = 2;
    ctx.strokeRect(menuX, menuY, menuWidth, menuHeight);

    // Options
    ctx.font = '14px Arial';
    for (let i = 0; i < this.options.length; i++) {
      const itemY = menuY + 5 + i * itemHeight;

      // Highlight selected
      if (i === this.selectedIndex) {
        ctx.fillStyle = 'rgba(100, 150, 255, 0.3)';
        ctx.fillRect(menuX + 2, itemY, menuWidth - 4, itemHeight - 2);
        ctx.strokeStyle = 'rgba(150, 200, 255, 0.8)';
        ctx.lineWidth = 1;
        ctx.strokeRect(menuX + 2, itemY, menuWidth - 4, itemHeight - 2);
      }

      ctx.fillStyle = i === this.selectedIndex ? 'rgba(255, 255, 255, 1)' : 'rgba(180, 180, 200, 0.8)';
      ctx.fillText(this.options[i], menuX + 10, itemY + 20);
    }
  }
}
