import { GameConfig } from '../config/GameConfig.ts';

interface LogEntry {
  message: string;
  timestamp: number;
}

/**
 * Scrolling combat log interface for displaying battle events.
 */
export class CombatLog {
  private entries: LogEntry[] = [];
  private maxEntries: number = 5;
  private messageLifetime: number = 5000; // ms

  addMessage(message: string): void {
    this.entries.push({
      message,
      timestamp: performance.now(),
    });

    if (this.entries.length > this.maxEntries) {
      this.entries.shift();
    }
  }

  update(time: number): void {
    // Fade out old messages
    this.entries = this.entries.filter(entry => time - entry.timestamp < this.messageLifetime);
  }

  render(ctx: CanvasRenderingContext2D, time: number): void {
    if (this.entries.length === 0) return;

    const cw = GameConfig.CANVAS_WIDTH;
    const ch = GameConfig.CANVAS_HEIGHT;
    const padding = 16;
    
    const startY = ch - 50 - (this.entries.length * 20); // Above bottom HUD

    ctx.textAlign = 'left';
    ctx.font = 'bold 13px monospace';

    for (let i = 0; i < this.entries.length; i++) {
      const entry = this.entries[i];
      const age = time - entry.timestamp;
      
      // Calculate alpha (fade out in last 1s)
      let alpha = 1.0;
      if (age > this.messageLifetime - 1000) {
        alpha = 1.0 - ((age - (this.messageLifetime - 1000)) / 1000);
      }

      const y = startY + (i * 20);

      // Text background outline for readability
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.fillStyle = 'rgba(0, 0, 0, 0.6)';
      ctx.fillRect(padding - 4, y - 12, ctx.measureText(entry.message).width + 8, 18);
      
      ctx.fillStyle = '#FFFFFF';
      ctx.fillText(entry.message, padding, y);
      ctx.restore();
    }
  }
}
