import { GameConfig } from '../config/GameConfig.ts';
import { UnitData } from '../core/Types.ts';
import { getAllUnitData } from '../database/UnitDatabase.ts';
import { EconomySystem } from '../economy/EconomySystem.ts';

// ─── Shop Menu ───────────────────────────────────────────────────────────────

export class ShopMenu {
  visible: boolean = false;
  items: UnitData[] = [];
  selectedIndex: number = 0;
  message: string = '';
  messageTimer: number = 0;

  open(): void {
    this.visible = true;
    this.items = getAllUnitData();
    this.selectedIndex = 0;
    this.message = '';
  }

  close(): void {
    this.visible = false;
  }

  moveSelection(dir: number): void {
    this.selectedIndex = Math.max(0, Math.min(this.items.length - 1, this.selectedIndex + dir));
  }

  getSelected(): UnitData {
    return this.items[this.selectedIndex];
  }

  update(dt: number): void {
    if (this.messageTimer > 0) {
      this.messageTimer -= dt / 1000;
      if (this.messageTimer <= 0) this.message = '';
    }
  }

  showMessage(msg: string): void {
    this.message = msg;
    this.messageTimer = 2;
  }

  render(ctx: CanvasRenderingContext2D, economy: EconomySystem): void {
    if (!this.visible) return;

    const cw = GameConfig.CANVAS_WIDTH;
    const ch = GameConfig.CANVAS_HEIGHT;

    // Overlay
    ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
    ctx.fillRect(0, 0, cw, ch);

    // Panel
    const pw = 500;
    const ph = 420;
    const px = (cw - pw) / 2;
    const py = (ch - ph) / 2;

    ctx.fillStyle = 'rgba(20, 25, 40, 0.95)';
    ctx.strokeStyle = '#5577AA';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.roundRect(px, py, pw, ph, 12);
    ctx.fill();
    ctx.stroke();

    // Title
    ctx.fillStyle = '#FFD700';
    ctx.font = 'bold 22px monospace';
    ctx.textAlign = 'center';
    ctx.fillText('🏪 SHOP', cw / 2, py + 30);

    // Gold
    ctx.fillStyle = '#FFD700';
    ctx.font = '14px monospace';
    ctx.fillText(`Gold: ${economy.gold}`, cw / 2, py + 52);

    // Items
    const startY = py + 80;
    for (let i = 0; i < this.items.length; i++) {
      const item = this.items[i];
      const iy = startY + i * 50;
      const isSelected = i === this.selectedIndex;

      if (isSelected) {
        ctx.fillStyle = 'rgba(80, 130, 220, 0.3)';
        ctx.beginPath();
        ctx.roundRect(px + 20, iy - 8, pw - 40, 44, 6);
        ctx.fill();
      }

      // Unit color dot
      ctx.fillStyle = item.color;
      ctx.beginPath();
      ctx.arc(px + 45, iy + 12, 12, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = '#FFF';
      ctx.font = 'bold 12px monospace';
      ctx.textAlign = 'center';
      ctx.fillText(item.name.charAt(0), px + 45, iy + 13);

      // Name & stats
      ctx.textAlign = 'left';
      ctx.fillStyle = isSelected ? '#FFFFFF' : '#8899AA';
      ctx.font = isSelected ? 'bold 14px monospace' : '14px monospace';
      ctx.fillText(item.name, px + 70, iy + 8);

      ctx.fillStyle = '#7788AA';
      ctx.font = '11px monospace';
      const ca = 10 + item.defense;
      ctx.fillText(
        `HP:${item.maxHP} ATK:${item.damageDice} CA:${ca} DEF:${item.defense} MOV:${item.movementRange} RNG:${item.attackRange}`,
        px + 70,
        iy + 26
      );

      // Cost
      const canAfford = economy.canAfford(item.cost);
      ctx.textAlign = 'right';
      ctx.fillStyle = canAfford ? '#FFD700' : '#FF4444';
      ctx.font = 'bold 14px monospace';
      ctx.fillText(`${item.cost}g`, px + pw - 30, iy + 14);
    }

    // Message
    if (this.message) {
      ctx.fillStyle = '#FFFFFF';
      ctx.font = 'bold 14px monospace';
      ctx.textAlign = 'center';
      ctx.fillText(this.message, cw / 2, py + ph - 30);
    }

    // Instructions
    ctx.fillStyle = '#556677';
    ctx.font = '11px monospace';
    ctx.textAlign = 'center';
    ctx.fillText('↑↓ Navigate  |  SPACE Purchase  |  ESC Close', cw / 2, py + ph - 10);
  }
}
